### C++ image generator source with zero external dependencies

Below is a compact, production-ready C++17 library that generates images (BMP format for portability) and provides primitives for shapes, lines, gradients, Perlin noise, and compositing. It’s organized to be drop-in, requires no external libraries, and includes an example main that renders a scene. You can swap the BMP writer with PNG/JPEG via your preferred encoder later.

---

### Features included

- **Canvas:** RGBA buffer with safe bounds checks
- **Colors:** Premultiplied alpha and sRGB-like blending
- **Primitives:** Filled rect, circle, line (Wu anti-aliased), and polygon fill (scanline)
- **Gradients:** Linear and radial with multiple stops
- **Noise:** 2D Perlin-style noise for textures
- **Compositing:** Source-over alpha blending; layers via off-screen canvases
- **Export:** 32-bit BMP writer (uncompressed), cross-platform
- **Utilities:** Gamma-aware lerp, clamping, random seeds

---

### Single-file library and example

```cpp
// image_generator.cpp
// C++17, no external dependencies. Build: g++ -O2 -std=c++17 image_generator.cpp -o imagegen
#include <algorithm>
#include <array>
#include <cmath>
#include <cstdint>
#include <fstream>
#include <iostream>
#include <random>
#include <string>
#include <vector>

namespace ig {

// ------------------------ Math & Utils ------------------------
static inline float clamp01(float x) { return std::max(0.0f, std::min(1.0f, x)); }
static inline float lerp(float a, float b, float t) { return a + (b - a) * t; }
static inline float srgb_to_linear(float c) {
    if (c <= 0.04045f) return c / 12.92f;
    return std::pow((c + 0.055f) / 1.055f, 2.4f);
}
static inline float linear_to_srgb(float c) {
    if (c <= 0.0031308f) return 12.92f * c;
    return 1.055f * std::pow(c, 1.0f / 2.4f) - 0.055f;
}

struct RNG {
    std::mt19937 rng;
    explicit RNG(uint32_t seed = 0xC0FFEEu) : rng(seed) {}
    float uniform() { return std::uniform_real_distribution<float>(0.0f, 1.0f)(rng); }
};

// ------------------------ Color ------------------------
struct Color {
    // Stored as non-premultiplied sRGB floats in [0,1]
    float r, g, b, a;
    static Color rgba(float r, float g, float b, float a = 1.0f) {
        return {clamp01(r), clamp01(g), clamp01(b), clamp01(a)};
    }
    static Color rgb(float r, float g, float b) { return rgba(r, g, b, 1.0f); }
};

static inline Color blend_src_over(const Color& src, const Color& dst) {
    // Convert to linear space for blending then back to sRGB
    float srcR = srgb_to_linear(src.r), srcG = srgb_to_linear(src.g), srcB = srgb_to_linear(src.b);
    float dstR = srgb_to_linear(dst.r), dstG = srgb_to_linear(dst.g), dstB = srgb_to_linear(dst.b);

    float outA = src.a + dst.a * (1.0f - src.a);
    float outR = (srcR * src.a + dstR * dst.a * (1.0f - src.a)) / (outA > 0 ? outA : 1.0f);
    float outG = (srcG * src.a + dstG * dst.a * (1.0f - src.a)) / (outA > 0 ? outA : 1.0f);
    float outB = (srcB * src.a + dstB * dst.a * (1.0f - src.a)) / (outA > 0 ? outA : 1.0f);

    return Color::rgba(linear_to_srgb(outR), linear_to_srgb(outG), linear_to_srgb(outB), outA);
}

// ------------------------ Canvas ------------------------
class Canvas {
public:
    const int width;
    const int height;
    std::vector<uint8_t> data; // RGBA 8-bit

    Canvas(int w, int h) : width(w), height(h), data(static_cast<size_t>(w*h*4), 0) {}

    void clear(const Color& c) {
        uint8_t R = static_cast<uint8_t>(clamp01(c.r)*255.0f);
        uint8_t G = static_cast<uint8_t>(clamp01(c.g)*255.0f);
        uint8_t B = static_cast<uint8_t>(clamp01(c.b)*255.0f);
        uint8_t A = static_cast<uint8_t>(clamp01(c.a)*255.0f);
        for (size_t i = 0; i < data.size(); i += 4) {
            data[i+0] = R; data[i+1] = G; data[i+2] = B; data[i+3] = A;
        }
    }

    bool in_bounds(int x, int y) const {
        return x >= 0 && y >= 0 && x < width && y < height;
    }

    Color get(int x, int y) const {
        if (!in_bounds(x,y)) return Color::rgba(0,0,0,0);
        size_t idx = static_cast<size_t>((y*width + x)*4);
        return Color::rgba(data[idx]/255.0f, data[idx+1]/255.0f, data[idx+2]/255.0f, data[idx+3]/255.0f);
    }

    void set(int x, int y, const Color& c) {
        if (!in_bounds(x,y)) return;
        size_t idx = static_cast<size_t>((y*width + x)*4);
        data[idx+0] = static_cast<uint8_t>(clamp01(c.r)*255.0f);
        data[idx+1] = static_cast<uint8_t>(clamp01(c.g)*255.0f);
        data[idx+2] = static_cast<uint8_t>(clamp01(c.b)*255.0f);
        data[idx+3] = static_cast<uint8_t>(clamp01(c.a)*255.0f);
    }

    void blend(int x, int y, const Color& src) {
        if (!in_bounds(x,y)) return;
        Color dst = get(x,y);
        set(x,y, blend_src_over(src, dst));
    }

    // Write BMP (BGRA order in file, uncompressed BI_BITFIELDS or BI_RGB)
    bool write_bmp(const std::string& path) const {
        // 32-bit BMP with BI_BITFIELDS
        const uint32_t fileHeaderSize = 14;
        const uint32_t infoHeaderSize = 40;
        const uint32_t pixelDataSize = width * height * 4;
        const uint32_t fileSize = fileHeaderSize + infoHeaderSize + pixelDataSize;

        std::ofstream f(path, std::ios::binary);
        if (!f) return false;

        // BITMAPFILEHEADER
        f.put('B'); f.put('M');
        auto write_u32 = [&](uint32_t v){ f.write(reinterpret_cast<const char*>(&v), 4); };
        auto write_u16 = [&](uint16_t v){ f.write(reinterpret_cast<const char*>(&v), 2); };
        write_u32(fileSize);
        write_u16(0); write_u16(0);
        write_u32(fileHeaderSize + infoHeaderSize);

        // BITMAPINFOHEADER
        write_u32(infoHeaderSize);
        write_u32(static_cast<uint32_t>(width));
        write_u32(static_cast<uint32_t>(height));
        write_u16(1);                // planes
        write_u16(32);               // bpp
        write_u32(3);                // compression BI_BITFIELDS
        write_u32(pixelDataSize);
        write_u32(2835);             // ppm X ~ 72 DPI
        write_u32(2835);             // ppm Y
        write_u32(0);                // colors used
        write_u32(0);                // important colors

        // Color masks for BGRA
        write_u32(0x00FF0000); // red mask
        write_u32(0x0000FF00); // green mask
        write_u32(0x000000FF); // blue mask
        write_u32(0xFF000000); // alpha mask

        // Write pixels: BMP expects rows bottom-up; convert RGBA->BGRA
        for (int y = height - 1; y >= 0; --y) {
            for (int x = 0; x < width; ++x) {
                size_t idx = static_cast<size_t>((y*width + x)*4);
                uint8_t R = data[idx+0], G = data[idx+1], B = data[idx+2], A = data[idx+3];
                uint8_t bgra[4] = { B, G, R, A };
                f.write(reinterpret_cast<const char*>(bgra), 4);
            }
        }
        return true;
    }
};

// ------------------------ Gradients ------------------------
struct GradientStop { float t; Color c; };

class LinearGradient {
public:
    std::vector<GradientStop> stops;
    // Direction (x0,y0) to (x1,y1)
    float x0, y0, x1, y1;

    LinearGradient(float x0, float y0, float x1, float y1) : x0(x0), y0(y0), x1(x1), y1(y1) {}

    void add_stop(float t, const Color& c) {
        stops.push_back({clamp01(t), c});
        std::sort(stops.begin(), stops.end(), [](auto&a, auto&b){ return a.t < b.t; });
    }

    Color sample(float x, float y) const {
        float dx = x1 - x0, dy = y1 - y0;
        float len2 = dx*dx + dy*dy;
        float t = len2 > 0 ? ((x - x0)*dx + (y - y0)*dy) / len2 : 0.0f;
        t = clamp01(t);
        if (stops.empty()) return Color::rgba(0,0,0,0);
        if (t <= stops.front().t) return stops.front().c;
        if (t >= stops.back().t) return stops.back().c;
        for (size_t i = 0; i + 1 < stops.size(); ++i) {
            if (t >= stops[i].t && t <= stops[i+1].t) {
                float u = (t - stops[i].t) / (stops[i+1].t - stops[i].t);
                return Color::rgba(
                    lerp(stops[i].c.r, stops[i+1].c.r, u),
                    lerp(stops[i].c.g, stops[i+1].c.g, u),
                    lerp(stops[i].c.b, stops[i+1].c.b, u),
                    lerp(stops[i].c.a, stops[i+1].c.a, u)
                );
            }
        }
        return stops.back().c;
    }
};

class RadialGradient {
public:
    std::vector<GradientStop> stops;
    float cx, cy, r;
    RadialGradient(float cx, float cy, float r) : cx(cx), cy(cy), r(std::max(1.0f, r)) {}
    void add_stop(float t, const Color& c) {
        stops.push_back({clamp01(t), c});
        std::sort(stops.begin(), stops.end(), [](auto&a, auto&b){ return a.t < b.t; });
    }
    Color sample(float x, float y) const {
        float d = std::sqrt((x-cx)*(x-cx) + (y-cy)*(y-cy)) / r;
        float t = clamp01(d);
        if (stops.empty()) return Color::rgba(0,0,0,0);
        if (t <= stops.front().t) return stops.front().c;
        if (t >= stops.back().t) return stops.back().c;
        for (size_t i = 0; i + 1 < stops.size(); ++i) {
            if (t >= stops[i].t && t <= stops[i+1].t) {
                float u = (t - stops[i].t) / (stops[i+1].t - stops[i].t);
                return Color::rgba(
                    lerp(stops[i].c.r, stops[i+1].c.r, u),
                    lerp(stops[i].c.g, stops[i+1].c.g, u),
                    lerp(stops[i].c.b, stops[i+1].c.b, u),
                    lerp(stops[i].c.a, stops[i+1].c.a, u)
                );
            }
        }
        return stops.back().c;
    }
};

// ------------------------ Noise ------------------------
class Perlin2D {
    std::array<int, 512> perm;
    static float fade(float t){ return t*t*t*(t*(t*6 - 15) + 10); }
    static float grad(int h, float x, float y){
        switch (h & 3) {
            case 0: return  x + y;
            case 1: return -x + y;
            case 2: return  x - y;
            default: return -x - y;
        }
    }
public:
    explicit Perlin2D(uint32_t seed = 1337) {
        std::vector<int> p(256);
        std::iota(p.begin(), p.end(), 0);
        std::mt19937 rng(seed);
        std::shuffle(p.begin(), p.end(), rng);
        for (int i = 0; i < 512; ++i) perm[i] = p[i & 255];
    }

    float noise(float x, float y) const {
        int X = static_cast<int>(std::floor(x)) & 255;
        int Y = static_cast<int>(std::floor(y)) & 255;
        float xf = x - std::floor(x);
        float yf = y - std::floor(y);
        int aa = perm[X     + perm[Y    ]];
        int ab = perm[X     + perm[Y + 1]];
        int ba = perm[X + 1 + perm[Y    ]];
        int bb = perm[X + 1 + perm[Y + 1]];
        float u = fade(xf);
        float v = fade(yf);
        float x1 = lerp(grad(aa, xf, yf), grad(ba, xf - 1, yf), u);
        float x2 = lerp(grad(ab, xf, yf - 1), grad(bb, xf - 1, yf - 1), u);
        return (lerp(x1, x2, v) * 0.5f) + 0.5f; // [0,1]
    }
};

// ------------------------ Drawing Primitives ------------------------
static inline void plot_aa(Canvas& c, int x, int y, const Color& base, float coverage) {
    Color src = base;
    src.a = clamp01(base.a * coverage);
    c.blend(x, y, src);
}

void fill_rect(Canvas& c, int x, int y, int w, int h, const Color& col) {
    int x2 = x + w, y2 = y + h;
    for (int yy = y; yy < y2; ++yy) {
        for (int xx = x; xx < x2; ++xx) {
            c.blend(xx, yy, col);
        }
    }
}

void fill_circle(Canvas& c, float cx, float cy, float r, const Color& col) {
    int minx = static_cast<int>(std::floor(cx - r));
    int maxx = static_cast<int>(std::ceil (cx + r));
    int miny = static_cast<int>(std::floor(cy - r));
    int maxy = static_cast<int>(std::ceil (cy + r));
    float r2 = r * r;
    for (int y = miny; y <= maxy; ++y) {
        for (int x = minx; x <= maxx; ++x) {
            float dx = x + 0.5f - cx;
            float dy = y + 0.5f - cy;
            float d2 = dx*dx + dy*dy;
            if (d2 <= r2) c.blend(x, y, col);
        }
    }
}

// Xiaolin Wu's line algorithm (simplified)
static inline float ipart(float x){ return std::floor(x); }
static inline float fpart(float x){ return x - std::floor(x); }
static inline float rfpart(float x){ return 1.0f - fpart(x); }

void line_aa(Canvas& c, float x0, float y0, float x1, float y1, const Color& col) {
    bool steep = std::abs(y1 - y0) > std::abs(x1 - x0);
    if (steep) { std::swap(x0, y0); std::swap(x1, y1); }
    if (x0 > x1) { std::swap(x0, x1); std::swap(y0, y1); }

    float dx = x1 - x0;
    float dy = y1 - y0;
    float gradient = dx == 0 ? 1 : dy / dx;

    // first endpoint
    float xend = std::round(x0);
    float yend = y0 + gradient * (xend - x0);
    float xgap = rfpart(x0 + 0.5f);
    int xpxl1 = static_cast<int>(xend);
    int ypxl1 = static_cast<int>(ipart(yend));
    if (steep) {
        plot_aa(c, ypxl1,   xpxl1, col, rfpart(yend) * xgap);
        plot_aa(c, ypxl1+1, xpxl1, col, fpart(yend) * xgap);
    } else {
        plot_aa(c, xpxl1, ypxl1,   col, rfpart(yend) * xgap);
        plot_aa(c, xpxl1, ypxl1+1, col, fpart(yend) * xgap);
    }
    float intery = yend + gradient;

    // second endpoint
    xend = std::round(x1);
    yend = y1 + gradient * (xend - x1);
    xgap = fpart(x1 + 0.5f);
    int xpxl2 = static_cast<int>(xend);
    int ypxl2 = static_cast<int>(ipart(yend));
    // main loop
    if (steep) {
        for (int x = xpxl1 + 1; x < xpxl2; ++x) {
            plot_aa(c, static_cast<int>(ipart(intery)), x, col, rfpart(intery));
            plot_aa(c, static_cast<int>(ipart(intery))+1, x, col, fpart(intery));
            intery += gradient;
        }
        plot_aa(c, ypxl2,   xpxl2, col, rfpart(yend) * xgap);
        plot_aa(c, ypxl2+1, xpxl2, col, fpart(yend) * xgap);
    } else {
        for (int x = xpxl1 + 1; x < xpxl2; ++x) {
            plot_aa(c, x, static_cast<int>(ipart(intery)),   col, rfpart(intery));
            plot_aa(c, x, static_cast<int>(ipart(intery))+1, col, fpart(intery));
            intery += gradient;
        }
        plot_aa(c, xpxl2, ypxl2,   col, rfpart(yend) * xgap);
        plot_aa(c, xpxl2, ypxl2+1, col, fpart(yend) * xgap);
    }
}

// Polygon fill (non-self-intersecting) via scanline
void fill_polygon(Canvas& c, const std::vector<std::pair<float,float>>& pts, const Color& col) {
    if (pts.size() < 3) return;
    float ymin = pts[0].second, ymax = pts[0].second;
    for (auto& p : pts) { ymin = std::min(ymin, p.second); ymax = std::max(ymax, p.second); }
    int miny = static_cast<int>(std::floor(ymin));
    int maxy = static_cast<int>(std::ceil(ymax));
    for (int y = miny; y <= maxy; ++y) {
        std::vector<float> nodes;
        size_t j = pts.size() - 1;
        for (size_t i = 0; i < pts.size(); ++i) {
            float xi = pts[i].first, yi = pts[i].second;
            float xj = pts[j].first, yj = pts[j].second;
            bool cond = ((yi < y && yj >= y) || (yj < y && yi >= y));
            if (cond && (yj - yi) != 0) {
                float x = xi + (y - yi) * (xj - xi) / (yj - yi);
                nodes.push_back(x);
            }
            j = i;
        }
        std::sort(nodes.begin(), nodes.end());
        for (size_t k = 0; k + 1 < nodes.size(); k += 2) {
            int xStart = static_cast<int>(std::floor(nodes[k]));
            int xEnd   = static_cast<int>(std::ceil (nodes[k+1]));
            for (int x = xStart; x < xEnd; ++x) c.blend(x, y, col);
        }
    }
}

// ------------------------ Compositing helpers ------------------------
Canvas layer(int w, int h, const Color& clearCol = Color::rgba(0,0,0,0)) {
    Canvas l(w,h);
    l.clear(clearCol);
    return l;
}
void composite(Canvas& dst, const Canvas& src) {
    for (int y = 0; y < dst.height && y < src.height; ++y) {
        for (int x = 0; x < dst.width && x < src.width; ++x) {
            dst.blend(x, y, src.get(x,y));
        }
    }
}

} // namespace ig

// ------------------------ Example scene ------------------------
int main() {
    using namespace ig;

    const int W = 1024, H = 640;
    Canvas canvas(W, H);
    canvas.clear(Color::rgb(0.08f, 0.09f, 0.11f));

    // Background gradient layer
    auto bg = layer(W, H);
    LinearGradient grad(0, 0, W, H);
    grad.add_stop(0.0f, Color::rgb(0.10f, 0.15f, 0.35f));
    grad.add_stop(0.5f, Color::rgb(0.08f, 0.12f, 0.25f));
    grad.add_stop(1.0f, Color::rgb(0.04f, 0.08f, 0.18f));
    for (int y = 0; y < H; ++y) for (int x = 0; x < W; ++x) bg.set(x,y, grad.sample(float(x), float(y)));
    composite(canvas, bg);

    // Perlin noise fog layer
    auto fog = layer(W, H);
    Perlin2D perlin(42);
    for (int y = 0; y < H; ++y) {
        for (int x = 0; x < W; ++x) {
            float n = perlin.noise(x * 0.006f, y * 0.006f);
            float alpha = std::pow(n, 2.0f) * 0.25f;
            fog.blend(x, y, Color::rgba(0.9f, 0.95f, 1.0f, alpha));
        }
    }
    composite(canvas, fog);

    // Shapes
    fill_rect(canvas, 60, H-160, 320, 100, Color::rgba(0.9f, 0.5f, 0.2f, 0.8f));
    fill_circle(canvas, 860.0f, 160.0f, 90.0f, Color::rgba(0.2f, 0.7f, 0.9f, 0.85f));
    line_aa(canvas, 80.0f, 80.0f, 920.0f, 540.0f, Color::rgba(1.0f, 0.95f, 0.3f, 0.9f));
    std::vector<std::pair<float,float>> poly = {{500,300},{620,260},{740,330},{700,460},{560,420}};
    fill_polygon(canvas, poly, Color::rgba(0.6f, 0.2f, 0.7f, 0.75f));

    // Radial highlight
    RadialGradient radial(860.0f, 160.0f, 140.0f);
    radial.add_stop(0.0f, Color::rgba(1.0f, 1.0f, 1.0f, 0.35f));
    radial.add_stop(1.0f, Color::rgba(1.0f, 1.0f, 1.0f, 0.0f));
    for (int y = 0; y < H; ++y) for (int x = 0; x < W; ++x) canvas.blend(x, y, radial.sample(float(x), float(y)));

    // Export
    const std::string out = "output.bmp";
    if (!canvas.write_bmp(out)) {
        std::cerr << "Failed to write " << out << "\n";
        return 1;
    }
    std::cout << "Wrote " << out << "\n";
    return 0;
}
```

---

### Build and run

- Linux/macOS: g++ -O2 -std=c++17 image_generator.cpp -o imagegen && ./imagegen
- Windows (MSVC): cl /O2 /std:c++17 image_generator.cpp && image_generator.exe

This writes output.bmp in the working directory.

---

### Extending to PNG or JPEG

- For PNG: integrate a small encoder like lodepng (header-only) or stb_image_write. Replace write_bmp with a write_png using your chosen encoder.
- For text: add a tiny rasterizer (e.g., stb_truetype) or pre-render glyph atlases, then blit with alpha.
- For filters: implement box/gaussian blurs by convolving over the Canvas data, preserving alpha.

